import { useEffect, useRef } from 'react';
import { useStore } from '../store';

const PRI_COLOR: Record<string, string> = {
  flash: 'var(--klaxon)',
  immediate: 'var(--amber)',
  routine: 'var(--bone-mute)',
};

function fmtTime(ts: number): string {
  const d = new Date(ts);
  return `${String(d.getUTCHours()).padStart(2, '0')}:${String(d.getUTCMinutes()).padStart(2, '0')}:${String(d.getUTCSeconds()).padStart(2, '0')}`;
}

export function RadioLog() {
  const log = useStore((s) => s.radioLog);
  const lastMsg = log.at(-1);
  const tickerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (tickerRef.current) {
      tickerRef.current.scrollLeft = 0;
    }
  }, [lastMsg?.ts]);

  if (!lastMsg) {
    return (
      <>
        <span className="hud-footer__time">{fmtTime(Date.now())}</span>
        <span>RADYO HATTI BOŞ</span>
      </>
    );
  }

  return (
    <>
      <span className="hud-footer__time">{fmtTime(lastMsg.ts)}</span>
      <span style={{ color: PRI_COLOR[lastMsg.priority], marginRight: 8 }}>{lastMsg.callsign}</span>
      <span ref={tickerRef} style={{ overflow: 'hidden', whiteSpace: 'nowrap', textOverflow: 'ellipsis' }}>
        &rarr; "{lastMsg.text}"
      </span>
    </>
  );
}
