import { useEffect, useRef } from 'react';
import type { Map as MapLibreMap } from 'maplibre-gl';
import { MapboxOverlay } from '@deck.gl/mapbox';
import type { Layer } from '@deck.gl/core';

interface DeckOverlayProps {
  map: MapLibreMap | null;
  layers: Layer[];
}

/**
 * Mount a deck.gl `MapboxOverlay` on top of a MapLibre map and keep its
 * layer list in sync with React state. The overlay automatically attaches
 * to MapLibre's WebGL context, so animations are GPU-driven.
 */
export function DeckOverlay({ map, layers }: DeckOverlayProps): null {
  const overlayRef = useRef<MapboxOverlay | null>(null);

  useEffect(() => {
    if (!map) return undefined;
    const overlay = new MapboxOverlay({ interleaved: true, layers });
    overlayRef.current = overlay;
    map.addControl(overlay as unknown as maplibregl.IControl);
    return () => {
      try {
        map.removeControl(overlay as unknown as maplibregl.IControl);
      } catch {
        /* ignore: map may already be torn down */
      }
      overlayRef.current = null;
    };
    // we intentionally don't depend on `layers` here - first effect mounts the overlay
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [map]);

  useEffect(() => {
    overlayRef.current?.setProps({ layers });
  }, [layers]);

  return null;
}
