import { create } from 'zustand';
import { subscribeWithSelector } from 'zustand/middleware';
import type {
  AirfieldFeature,
  BeatFeature,
  CameraFeature,
  CorridorFeature,
  IncidentFeature,
  PadFeature,
  PortFeature,
  SeaLaneFeature,
  UnitFeature,
  VenueFeature,
} from '../types/venue';
import type { BuildingFeature } from '../map/layers/buildings3dLayer';
import { loadFavoriteIds, saveFavoriteIds, toggleFavoriteId } from '../lib/favorites';

export type TabId =
  | 'operasyon'
  | 'goruntuleme'
  | 'haberlesme'
  | 'adli'
  | 'kayit'
  | 'altyapi'
  | 'c2'
  | 'kure';

export interface RadioMessage {
  ts: number;
  callsign: string;
  text: string;
  priority: 'flash' | 'immediate' | 'routine';
}

interface StaticGeo {
  pads: PadFeature[];
  ports: PortFeature[];
  airfields: AirfieldFeature[];
  airCorridors: CorridorFeature[];
  seaLanes: SeaLaneFeature[];
  groundBeats: BeatFeature[];
  cameras: CameraFeature[];
  buildings: BuildingFeature[]; // lazy-populated
}

export interface AppState {
  activeTab: TabId;
  bufferEnabled: boolean;
  bufferRadiusKm: number;
  searchQuery: string;
  selectedVenueId: string | null;
  selectedUnitId: string | null;
  selectedIncidentId: string | null;
  selectedCameraId: string | null;
  buildings3dEnabled: boolean;
  camerasEnabled: boolean;
  favorites: Set<string>;
  reducedMotion: boolean;

  venues: VenueFeature[];
  units: UnitFeature[];
  incidents: IncidentFeature[];
  staticGeo: StaticGeo;
  radioLog: RadioMessage[];
  kpis: {
    units: number;
    incidents: number;
    etaAvgSec: number;
    bedsAvailable: number;
    roadsBlockedPct: number;
    wxLabel: string;
  };
  sparklines: {
    units: number[];
    incidents: number[];
    eta: number[];
    beds: number[];
    roads: number[];
  };

  setActiveTab(id: TabId): void;
  setSearchQuery(q: string): void;
  setBufferEnabled(on: boolean): void;
  toggleBuffer(): void;
  setBufferRadius(km: number): void;
  selectVenue(id: string | null): void;
  selectUnit(id: string | null): void;
  selectIncident(id: string | null): void;
  selectCamera(id: string | null): void;
  toggleBuildings3d(): void;
  toggleCameras(): void;
  toggleFavorite(id: string): void;
  setVenues(v: VenueFeature[]): void;
  setUnits(u: UnitFeature[]): void;
  setIncidents(i: IncidentFeature[]): void;
  setStaticGeo(g: Partial<StaticGeo>): void;
  setBuildings(b: BuildingFeature[]): void;
  pushRadio(msg: RadioMessage): void;
  tickSparklines(samples: Partial<AppState['sparklines']>): void;
  setReducedMotion(on: boolean): void;
}

const SPARK_LEN = 60;

function rolling(prev: number[], value: number): number[] {
  const next = [...prev, value];
  if (next.length > SPARK_LEN) next.splice(0, next.length - SPARK_LEN);
  return next;
}

export const useStore = create<AppState>()(
  subscribeWithSelector((set) => ({
    activeTab: 'operasyon',
    bufferEnabled: false,
    bufferRadiusKm: 1.5,
    searchQuery: '',
    selectedVenueId: null,
    selectedUnitId: null,
    selectedIncidentId: null,
    selectedCameraId: null,
    buildings3dEnabled: true,
    camerasEnabled: true,
    favorites: typeof window !== 'undefined' ? loadFavoriteIds() : new Set(),
    reducedMotion:
      typeof window !== 'undefined' &&
      window.matchMedia?.('(prefers-reduced-motion: reduce)').matches === true,

    venues: [],
    units: [],
    incidents: [],
    staticGeo: {
      pads: [],
      ports: [],
      airfields: [],
      airCorridors: [],
      seaLanes: [],
      groundBeats: [],
      cameras: [],
      buildings: [],
    },
    radioLog: [],
    kpis: {
      units: 0,
      incidents: 0,
      etaAvgSec: 0,
      bedsAvailable: 0,
      roadsBlockedPct: 0,
      wxLabel: '--',
    },
    sparklines: { units: [], incidents: [], eta: [], beds: [], roads: [] },

    setActiveTab: (id) => set({ activeTab: id }),
    setSearchQuery: (q) => set({ searchQuery: q }),
    setBufferEnabled: (on) => set({ bufferEnabled: on }),
    toggleBuffer: () => set((s) => ({ bufferEnabled: !s.bufferEnabled })),
    setBufferRadius: (km) => set({ bufferRadiusKm: km }),
    selectVenue: (id) => set({ selectedVenueId: id }),
    selectUnit: (id) => set({ selectedUnitId: id }),
    selectIncident: (id) => set({ selectedIncidentId: id }),
    selectCamera: (id) => set({ selectedCameraId: id }),
    toggleBuildings3d: () => set((s) => ({ buildings3dEnabled: !s.buildings3dEnabled })),
    toggleCameras: () => set((s) => ({ camerasEnabled: !s.camerasEnabled })),
    toggleFavorite: (id) =>
      set((s) => {
        const next = new Set(s.favorites);
        toggleFavoriteId(next, id);
        saveFavoriteIds(next);
        return { favorites: next };
      }),
    setVenues: (v) => set({ venues: v }),
    setUnits: (u) => set((s) => ({ units: u, kpis: { ...s.kpis, units: u.length } })),
    setIncidents: (i) =>
      set((s) => ({ incidents: i, kpis: { ...s.kpis, incidents: i.length } })),
    setStaticGeo: (g) => set((s) => ({ staticGeo: { ...s.staticGeo, ...g } })),
    setBuildings: (b) => set((s) => ({ staticGeo: { ...s.staticGeo, buildings: b } })),
    pushRadio: (msg) =>
      set((s) => {
        const next = [...s.radioLog, msg];
        if (next.length > 200) next.splice(0, next.length - 200);
        return { radioLog: next };
      }),
    tickSparklines: (samples) =>
      set((s) => ({
        sparklines: {
          units: samples.units
            ? rolling(s.sparklines.units, samples.units.at(-1) ?? 0)
            : s.sparklines.units,
          incidents: samples.incidents
            ? rolling(s.sparklines.incidents, samples.incidents.at(-1) ?? 0)
            : s.sparklines.incidents,
          eta: samples.eta ? rolling(s.sparklines.eta, samples.eta.at(-1) ?? 0) : s.sparklines.eta,
          beds: samples.beds
            ? rolling(s.sparklines.beds, samples.beds.at(-1) ?? 0)
            : s.sparklines.beds,
          roads: samples.roads
            ? rolling(s.sparklines.roads, samples.roads.at(-1) ?? 0)
            : s.sparklines.roads,
        },
      })),
    setReducedMotion: (on) => set({ reducedMotion: on }),
  })),
);
