import { useStore } from '../store';

const WX_ROTATION = ['⛅ 14°', '⛅ 13°', '🌧 12°', '🌧 11°', '🌫 10°'];

/**
 * Lightweight KPI animator. Pulls a few synthetic numbers each second so the
 * ribbon shows movement even without backend telemetry.
 */
export function startKpiPump(getReducedMotion: () => boolean): () => void {
  let beds = 1284;
  let eta = 252;
  let roads = 23;
  let wxIdx = 0;
  let tick = 0;

  const id = window.setInterval(() => {
    if (getReducedMotion() && tick > 0 && tick % 4 !== 0) {
      tick++;
      return;
    }
    tick++;
    beds += Math.round((Math.random() - 0.5) * 24);
    beds = Math.max(800, Math.min(2200, beds));
    eta += Math.round((Math.random() - 0.5) * 8);
    eta = Math.max(120, Math.min(560, eta));
    roads += (Math.random() - 0.5) * 1.6;
    roads = Math.max(2, Math.min(58, roads));
    if (tick % 30 === 0) {
      wxIdx = (wxIdx + 1) % WX_ROTATION.length;
    }

    const state = useStore.getState();
    useStore.setState({
      kpis: {
        units: state.units.length,
        incidents: state.incidents.length,
        etaAvgSec: eta,
        bedsAvailable: beds,
        roadsBlockedPct: roads,
        wxLabel: WX_ROTATION[wxIdx] ?? '--',
      },
    });
    state.tickSparklines({
      units: [state.units.length],
      incidents: [state.incidents.length],
      eta: [eta],
      beds: [beds],
      roads: [roads],
    });
  }, 1000);

  return () => window.clearInterval(id);
}
