import { Search } from 'lucide-react';
import { useStore } from '../store';

export function SearchBar() {
  const query = useStore((s) => s.searchQuery);
  const setQuery = useStore((s) => s.setSearchQuery);

  return (
    <div className="search-host glass-panel glass-panel--float glass-panel--pill">
      <div className="search-host__wrap">
        <Search size={14} style={{ color: 'var(--bone-faint)', flexShrink: 0 }} />
        <input
          data-testid="search-input"
          type="search"
          placeholder="Mekan ara..."
          aria-label="Mekan ara"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />
      </div>
    </div>
  );
}
