import { Building2, Camera, CircleDashed } from 'lucide-react';
import { useStore } from '../store';

interface ToggleBtnProps {
  testId?: string;
  on: boolean;
  onClick: () => void;
  label: string;
  icon: React.ReactNode;
}

function ToggleBtn({ testId, on, onClick, label, icon }: ToggleBtnProps) {
  return (
    <button
      type="button"
      data-testid={testId}
      className={`map-toolbar__btn glass-panel glass-panel--float glass-panel--pill glass-panel--interactive ${on ? 'is-active glass-panel--amber' : ''}`}
      aria-pressed={on}
      onClick={onClick}
    >
      {icon}
      {label}
    </button>
  );
}

export function MapToolbar() {
  const bufferOn = useStore((s) => s.bufferEnabled);
  const toggleBuffer = useStore((s) => s.toggleBuffer);
  const buildingsOn = useStore((s) => s.buildings3dEnabled);
  const toggleBuildings = useStore((s) => s.toggleBuildings3d);
  const camerasOn = useStore((s) => s.camerasEnabled);
  const toggleCameras = useStore((s) => s.toggleCameras);

  return (
    <div className="map-toolbar">
      <ToggleBtn
        testId="buffer-toggle"
        on={bufferOn}
        onClick={toggleBuffer}
        label="Buffer"
        icon={<CircleDashed size={12} />}
      />
      <ToggleBtn
        testId="buildings3d-toggle"
        on={buildingsOn}
        onClick={toggleBuildings}
        label="3D Bina"
        icon={<Building2 size={12} />}
      />
      <ToggleBtn
        testId="cameras-toggle"
        on={camerasOn}
        onClick={toggleCameras}
        label="Kameralar"
        icon={<Camera size={12} />}
      />
    </div>
  );
}
