import { useEffect, useMemo, useRef, useState } from 'react';
import type { Map as MapLibreMap } from 'maplibre-gl';
import type { Layer } from '@deck.gl/core';
import { createGlobeMap, flyToRegion, GLOBE_HOME, GLOBE_INITIAL_ZOOM } from './globeController';
import { DeckOverlay } from './deckOverlay';
import { buildHeliPadsLayer } from './layers/heliPadsLayer';
import { buildPortsLayer } from './layers/portsLayer';
import { buildAirfieldsLayer } from './layers/airfieldsLayer';
import { buildIncidentsLayers } from './layers/incidentsPulseLayer';
import { buildPatrolsLayer } from './layers/patrolsLayer';
import { buildCamerasLayer } from './layers/camerasLayer';
import { useStore } from '../store';
import type { UnitState } from '../types/venue';

interface GlobeHostProps {
  unitSnapshot: UnitState[];
  pulseT: number;
}

interface GlobePreset {
  id: string;
  label: string;
  center: [number, number];
  zoom: number;
}

const PRESETS: GlobePreset[] = [
  { id: 'globe',  label: 'Küre',        center: GLOBE_HOME,     zoom: GLOBE_INITIAL_ZOOM },
  { id: 'avrasya',label: 'Avrasya',     center: [40, 45],       zoom: 3.0 },
  { id: 'tr',     label: 'Türkiye',     center: [35.3, 39.0],   zoom: 5.2 },
  { id: 'marmara',label: 'Marmara',     center: [28.5, 40.7],   zoom: 7.4 },
  { id: 'ist',    label: 'İstanbul',    center: [28.98, 41.04], zoom: 10.4 },
];

/**
 * Küre tab map: MapLibre v5 globe projection with NASA GIBS BlueMarble
 * basemap, AWS terrain, atmosphere/sky, and the same deck.gl operational
 * overlay (heli pads, ports, airfields, incidents, patrols, cameras)
 * projected onto the sphere.
 */
export function GlobeHost({ unitSnapshot, pulseT }: GlobeHostProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<MapLibreMap | null>(null);
  const [mapReady, setMapReady] = useState<MapLibreMap | null>(null);
  const [activePreset, setActivePreset] = useState<string>('globe');

  const incidents = useStore((s) => s.incidents);
  const staticGeo = useStore((s) => s.staticGeo);
  const selectIncident = useStore((s) => s.selectIncident);
  const selectUnit = useStore((s) => s.selectUnit);
  const selectCamera = useStore((s) => s.selectCamera);
  const selectedIncidentId = useStore((s) => s.selectedIncidentId);
  const selectedUnitId = useStore((s) => s.selectedUnitId);
  const selectedCameraId = useStore((s) => s.selectedCameraId);
  const camerasEnabled = useStore((s) => s.camerasEnabled);

  useEffect(() => {
    if (!containerRef.current) return undefined;
    const map = createGlobeMap({ container: containerRef.current });
    mapRef.current = map;
    map.once('load', () => setMapReady(map));
    return () => {
      map.remove();
      mapRef.current = null;
      setMapReady(null);
    };
  }, []);

  const layers = useMemo<Layer[]>(() => {
    const out: Layer[] = [];
    out.push(buildHeliPadsLayer(staticGeo.pads));
    out.push(buildPortsLayer(staticGeo.ports));
    out.push(buildAirfieldsLayer(staticGeo.airfields));
    if (camerasEnabled && staticGeo.cameras.length > 0) {
      out.push(
        ...buildCamerasLayer({
          data: staticGeo.cameras,
          selectedId: selectedCameraId,
          onClick: selectCamera,
        }),
      );
    }
    out.push(
      ...buildIncidentsLayers({
        data: incidents,
        pulseT,
        selectedId: selectedIncidentId,
        onClick: selectIncident,
      }),
    );
    out.push(
      ...buildPatrolsLayer({
        data: unitSnapshot,
        selectedId: selectedUnitId,
        onClick: selectUnit,
      }),
    );
    return out;
  }, [
    staticGeo,
    camerasEnabled,
    selectedCameraId,
    selectCamera,
    incidents,
    pulseT,
    selectedIncidentId,
    selectIncident,
    unitSnapshot,
    selectedUnitId,
    selectUnit,
  ]);

  const handlePreset = (preset: GlobePreset) => {
    setActivePreset(preset.id);
    if (mapReady) flyToRegion(mapReady, preset.center, preset.zoom);
  };

  return (
    <section className="hud-pane hud-pane--map" style={{ gridColumn: '1 / -1' }}>
      <div className="map-host">
        <div ref={containerRef} className="map-canvas" />
        <DeckOverlay map={mapReady} layers={layers} />

        <div className="map-toolbar" style={{ display: 'flex', gap: 8 }}>
          {PRESETS.map((p) => (
            <button
              key={p.id}
              type="button"
              className={`map-toolbar__btn glass-panel glass-panel--float glass-panel--pill glass-panel--interactive ${activePreset === p.id ? 'is-active glass-panel--amber' : ''}`}
              onClick={() => handlePreset(p)}
              aria-pressed={activePreset === p.id}
            >
              {p.label}
            </button>
          ))}
        </div>

        <div
          className="glass-panel glass-panel--float glass-panel--pill"
          style={{
            position: 'absolute',
            top: 14,
            right: 14,
            padding: '8px 14px',
            fontFamily: 'var(--font-mono)',
            fontSize: 'var(--t-tiny)',
            letterSpacing: '0.12em',
            textTransform: 'uppercase',
            color: 'var(--bone-mute)',
          }}
        >
          NASA · BlueMarble · GIBS · {staticGeo.cameras.length} Kamera
        </div>

        <div className="map-watermark">
          AKOM · MAPLIBRE V5 · GLOBE · {unitSnapshot.length} BİRİM ·{' '}
          {staticGeo.cameras.length} KAMERA
        </div>
      </div>
    </section>
  );
}
