import maplibregl, { Map as MapLibreMap } from 'maplibre-gl';
import type { StyleSpecification } from 'maplibre-gl';

const ISTANBUL_CENTER: [number, number] = [28.9912, 41.0470];
const DEFAULT_ZOOM = 13.2;
const DEFAULT_PITCH = 55;
const DEFAULT_BEARING = -12;

/**
 * Dark MapLibre style backed by CARTO's public dark-matter raster tiles.
 *
 * We use raster tiles instead of vector PMTiles in v1 to keep the cockpit
 * boot fast on first run; PMTiles can swap in via VITE_TILES_URL.
 */
function defaultStyle(): StyleSpecification {
  return {
    version: 8,
    sources: {
      'carto-dark': {
        type: 'raster',
        tiles: [
          'https://a.basemaps.cartocdn.com/dark_nolabels/{z}/{x}/{y}@2x.png',
          'https://b.basemaps.cartocdn.com/dark_nolabels/{z}/{x}/{y}@2x.png',
          'https://c.basemaps.cartocdn.com/dark_nolabels/{z}/{x}/{y}@2x.png',
          'https://d.basemaps.cartocdn.com/dark_nolabels/{z}/{x}/{y}@2x.png',
        ],
        tileSize: 256,
        attribution:
          '© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> · © <a href="https://carto.com/attributions">CARTO</a>',
      },
      'carto-labels': {
        type: 'raster',
        tiles: [
          'https://a.basemaps.cartocdn.com/dark_only_labels/{z}/{x}/{y}@2x.png',
          'https://b.basemaps.cartocdn.com/dark_only_labels/{z}/{x}/{y}@2x.png',
          'https://c.basemaps.cartocdn.com/dark_only_labels/{z}/{x}/{y}@2x.png',
        ],
        tileSize: 256,
      },
    },
    glyphs: 'https://demotiles.maplibre.org/font/{fontstack}/{range}.pbf',
    layers: [
      {
        id: 'bg',
        type: 'background',
        paint: { 'background-color': '#060912' },
      },
      {
        id: 'tiles-dark',
        type: 'raster',
        source: 'carto-dark',
        paint: { 'raster-opacity': 0.82, 'raster-saturation': -0.35 },
      },
      {
        id: 'tiles-labels',
        type: 'raster',
        source: 'carto-labels',
        paint: { 'raster-opacity': 0.7 },
        minzoom: 9,
      },
    ],
  };
}

export interface CreateMapOptions {
  container: HTMLDivElement;
  center?: [number, number];
  zoom?: number;
  bearing?: number;
  pitch?: number;
  styleUrl?: string;
}

export function createMap(opts: CreateMapOptions): MapLibreMap {
  const style = opts.styleUrl ?? defaultStyle();
  const map = new maplibregl.Map({
    container: opts.container,
    style: style as StyleSpecification,
    center: opts.center ?? ISTANBUL_CENTER,
    zoom: opts.zoom ?? DEFAULT_ZOOM,
    bearing: opts.bearing ?? DEFAULT_BEARING,
    pitch: opts.pitch ?? DEFAULT_PITCH,
    minZoom: 8,
    maxZoom: 19,
    maxPitch: 75,
    attributionControl: { compact: true },
    fadeDuration: 80,
    hash: false,
  });

  map.addControl(
    new maplibregl.NavigationControl({ visualizePitch: true, showCompass: true }),
    'bottom-right',
  );
  map.addControl(new maplibregl.ScaleControl({ unit: 'metric' }), 'bottom-left');

  map.dragRotate.enable();
  map.touchZoomRotate.enableRotation();

  return map;
}

export function flyToVenue(map: MapLibreMap, lng: number, lat: number): void {
  map.flyTo({
    center: [lng, lat],
    zoom: Math.max(map.getZoom(), 13),
    pitch: 45,
    bearing: 0,
    speed: 1.2,
    curve: 1.4,
  });
}

export { ISTANBUL_CENTER, DEFAULT_ZOOM };
