import { ScatterplotLayer } from '@deck.gl/layers';
import type { VenueFeature } from '../../types/venue';

const AMBER: [number, number, number] = [255, 176, 0];
const AMBER_DIM: [number, number, number] = [120, 84, 0];

interface VenuesLayerOptions {
  venues: VenueFeature[];
  selectedId?: string | null;
  onClick?: (id: string) => void;
  filterIds?: Set<string> | null;
}

export function buildVenuesLayer({
  venues,
  selectedId = null,
  onClick,
  filterIds = null,
}: VenuesLayerOptions): ScatterplotLayer<VenueFeature> {
  return new ScatterplotLayer<VenueFeature>({
    id: 'venues',
    data: venues,
    pickable: true,
    stroked: true,
    filled: true,
    radiusUnits: 'pixels',
    lineWidthUnits: 'pixels',
    getPosition: (f) => f.geometry.coordinates as [number, number],
    getFillColor: (f) => {
      const id = f.properties.id;
      const dim = filterIds && !filterIds.has(id);
      if (selectedId === id) return [...AMBER, 240];
      return [...(dim ? AMBER_DIM : AMBER), dim ? 90 : 180];
    },
    getLineColor: (f) => (selectedId === f.properties.id ? [255, 255, 255, 220] : [...AMBER, 200]),
    getRadius: (f) => (selectedId === f.properties.id ? 9 : 6),
    getLineWidth: (f) => (selectedId === f.properties.id ? 2 : 1),
    onClick: (info) => {
      const id = info.object?.properties.id;
      if (id) onClick?.(id);
    },
    updateTriggers: {
      getFillColor: [selectedId, filterIds],
      getLineColor: [selectedId],
      getRadius: [selectedId],
      getLineWidth: [selectedId],
    },
  });
}
