import { PathLayer } from '@deck.gl/layers';
import type { SeaLaneFeature } from '../../types/venue';

interface LaneRow {
  id: string;
  path: [number, number][];
  kind: SeaLaneFeature['properties']['kind'];
}

export function buildSeaLanesLayer(features: SeaLaneFeature[]): PathLayer<LaneRow> {
  const rows: LaneRow[] = features.map((f) => ({
    id: f.properties.id,
    kind: f.properties.kind,
    path: (f.geometry.coordinates as [number, number][]).map(([lon, lat]) => [lon, lat]),
  }));
  return new PathLayer<LaneRow>({
    id: 'sea-lanes',
    data: rows,
    pickable: false,
    widthUnits: 'pixels',
    getPath: (d) => d.path,
    getColor: (d) =>
      d.kind === 'shuttle' ? [107, 182, 255, 110] : [107, 182, 255, 70],
    getWidth: 1.2,
    capRounded: true,
    jointRounded: true,
  });
}
