import * as turf from '@turf/turf';
import type { Feature, Polygon, MultiPolygon } from 'geojson';

export const DEFAULT_BUFFER_KM = 1.5;

export type BufferPolygon = Feature<Polygon | MultiPolygon>;

export function bufferAroundPoint(lng: number, lat: number, radiusKm: number): BufferPolygon {
  const pt = turf.point([lng, lat]);
  const result = turf.buffer(pt, radiusKm, { units: 'kilometers' });
  if (!result) {
    throw new Error('turf.buffer returned undefined');
  }
  return result as BufferPolygon;
}

export function pointInBuffer(lng: number, lat: number, polygon: BufferPolygon): boolean {
  const pt = turf.point([lng, lat]);
  return turf.booleanPointInPolygon(pt, polygon);
}
