import { useEffect, useRef, useState } from 'react';
import { PatrolEngine } from './PatrolEngine';
import type { UnitState } from '../types/venue';

interface UsePatrolEngineArgs {
  engine: PatrolEngine;
  /** Frequency at which React state ticks. GPU still runs at 60fps. */
  reactHz?: number;
  reducedMotion?: boolean;
  enabled?: boolean;
}

/**
 * Drives the engine and exposes the latest snapshot for React consumers.
 * Default: snapshot React state at 10Hz so layers update at human-visible
 * cadence without burning RAF. Reduced motion lowers to 2Hz and freezes
 * the snapshot between ticks.
 */
export function usePatrolEngine({
  engine,
  reactHz = 10,
  reducedMotion = false,
  enabled = true,
}: UsePatrolEngineArgs): UnitState[] {
  const [snapshot, setSnapshot] = useState<UnitState[]>(() => engine.snapshot());
  const lastTickRef = useRef(0);

  useEffect(() => {
    if (!enabled) return undefined;
    const hz = reducedMotion ? 2 : reactHz;
    const intervalMs = 1000 / hz;
    let raf = 0;
    const tick = () => {
      const now = performance.now();
      if (now - lastTickRef.current >= intervalMs) {
        lastTickRef.current = now;
        setSnapshot(engine.snapshot(now));
      }
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [engine, reactHz, reducedMotion, enabled]);

  return snapshot;
}
