import { useMemo } from 'react';
import { useStore } from '../store';
import { VenueCard } from './VenueCard';

export function VenueList() {
  const venues = useStore((s) => s.venues);
  const query = useStore((s) => s.searchQuery);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return venues;
    return venues.filter((v) => v.properties.name.toLowerCase().includes(q));
  }, [venues, query]);

  if (filtered.length === 0 && query) {
    return (
      <div className="ops-panel__title" style={{ marginTop: 12 }}>
        "{query}" için eşleşme yok
      </div>
    );
  }

  return (
    <div className="venue-list">
      {filtered.map((v) => (
        <VenueCard key={v.properties.id} venue={v} />
      ))}
    </div>
  );
}
