import type { RadioMessage } from '../store';

const CALLSIGNS = [
  'ALPHA-3',
  'BRAVO-1',
  'CHARLIE-7',
  'DELTA-4',
  'EAGLE-2',
  'FOXTROT-6',
  'KRAL-1',
  'MARMARA-9',
];

const ROUTINE_LINES = [
  'sektör 3 kontrol, hareket yok',
  'rota üzerinde, ETA 04 dakika',
  'koordineli devriye, tüm birimler etkin',
  'liman çıkışı temiz, devam',
  'koridor 2 üzerinde, irtifa 280 metre',
];

const IMMEDIATE_LINES = [
  'Pendik istasyonu, hat 4 açık, yardımcı tim talep ediyoruz',
  'Mecidiyeköy köprüsünde trafik durdu, alternatif yönlendirin',
  'Avcılar L7 mahallesi, üç kat çökme, tıbbi öncelik',
  'hava operasyonu, helikopter LZ-3 inişe yaklaşıyor',
];

const FLASH_LINES = [
  'MASCAL aktivasyonu Şişli — tüm birimler dispatch için bekleyin',
  'kritik kontrol noktası 7, sismik artçı tespit edildi',
];

function pick<T>(arr: readonly T[]): T {
  const i = Math.floor(Math.random() * arr.length);
  return arr[i] ?? arr[0]!;
}

export function generateRadio(now = Date.now()): RadioMessage {
  const r = Math.random();
  let priority: RadioMessage['priority'] = 'routine';
  let text = pick(ROUTINE_LINES);
  if (r > 0.92) {
    priority = 'flash';
    text = pick(FLASH_LINES);
  } else if (r > 0.7) {
    priority = 'immediate';
    text = pick(IMMEDIATE_LINES);
  }
  return {
    ts: now,
    callsign: pick(CALLSIGNS),
    text,
    priority,
  };
}
