import { ScatterplotLayer } from '@deck.gl/layers';
import type { Modality, UnitState } from '../../types/venue';

const MODALITY_COLOR: Record<Modality, [number, number, number]> = {
  ground: [255, 176, 0],
  heli: [255, 220, 110],
  fixed: [200, 180, 255],
  naval: [107, 182, 255],
};

interface PatrolsArgs {
  data: UnitState[];
  selectedId?: string | null;
  onClick?: (id: string) => void;
}

export function buildPatrolsLayer({
  data,
  selectedId = null,
  onClick,
}: PatrolsArgs): ScatterplotLayer<UnitState>[] {
  const halo = new ScatterplotLayer<UnitState>({
    id: 'patrols-halo',
    data,
    pickable: false,
    stroked: false,
    filled: true,
    radiusUnits: 'pixels',
    getPosition: (u) => [u.lon, u.lat],
    getRadius: (u) => (u.modality === 'fixed' ? 9 : 7),
    getFillColor: (u) => {
      const c = MODALITY_COLOR[u.modality];
      return [c[0], c[1], c[2], 50];
    },
    updateTriggers: {
      getPosition: data,
    },
  });

  const core = new ScatterplotLayer<UnitState>({
    id: 'patrols-core',
    data,
    pickable: true,
    stroked: true,
    filled: true,
    radiusUnits: 'pixels',
    lineWidthUnits: 'pixels',
    getPosition: (u) => [u.lon, u.lat],
    getRadius: (u) => {
      if (selectedId === u.id) return 6;
      return u.modality === 'fixed' ? 5 : 3.5;
    },
    getFillColor: (u) => {
      const c = MODALITY_COLOR[u.modality];
      return [c[0], c[1], c[2], 240];
    },
    getLineColor: (u) =>
      selectedId === u.id ? [255, 255, 255, 240] : [10, 12, 16, 200],
    getLineWidth: 1.2,
    onClick: (info) => {
      const id = info.object?.id;
      if (id) onClick?.(id);
    },
    updateTriggers: {
      getPosition: data,
      getRadius: [selectedId],
      getLineColor: [selectedId],
    },
  });

  return [halo, core];
}
