import { Star, StarOff } from 'lucide-react';
import type { VenueFeature } from '../types/venue';
import { useStore } from '../store';

interface VenueCardProps {
  venue: VenueFeature;
}

export function VenueCard({ venue }: VenueCardProps) {
  const { id, name } = venue.properties;
  const capacity = (venue.properties as { capacity?: number }).capacity;
  const venueType = (venue.properties as { venueType?: string }).venueType;
  const rating = (venue.properties as { rating?: number }).rating;

  const selectedId = useStore((s) => s.selectedVenueId);
  const select = useStore((s) => s.selectVenue);
  const favorites = useStore((s) => s.favorites);
  const toggleFavorite = useStore((s) => s.toggleFavorite);

  const isFav = favorites.has(id);
  const isActive = selectedId === id;

  return (
    <button
      type="button"
      className="venue-card glass-panel glass-panel--card glass-panel--interactive"
      data-testid="venue-card"
      data-active={isActive}
      onClick={() => select(id)}
      aria-current={isActive ? 'true' : undefined}
    >
      <span
        className={`venue-card__star ${isFav ? 'is-on' : ''}`}
        onClick={(e) => {
          e.stopPropagation();
          toggleFavorite(id);
        }}
        role="button"
        aria-label={isFav ? 'Favorilerden çıkar' : 'Favorilere ekle'}
      >
        {isFav ? <Star size={12} fill="currentColor" /> : <StarOff size={12} />}
      </span>
      <div className="venue-card__name">{name}</div>
      <div className="venue-card__meta">
        {venueType ?? '--'}
        {capacity ? ` · KAP ${capacity}` : ''}
        {typeof rating === 'number' ? ` · ★ ${rating.toFixed(1)}` : ''}
      </div>
    </button>
  );
}
