import { useEffect, useMemo, useRef, useState } from 'react';
import type { Map as MapLibreMap } from 'maplibre-gl';
import type { Layer } from '@deck.gl/core';
import { createMap, flyToVenue } from './mapController';
import { DeckOverlay } from './deckOverlay';
import { buildVenuesLayer } from './layers/venuesLayer';
import { buildBufferLayer } from './layers/bufferLayer';
import { buildHeliPadsLayer } from './layers/heliPadsLayer';
import { buildPortsLayer } from './layers/portsLayer';
import { buildAirfieldsLayer } from './layers/airfieldsLayer';
import { buildAirCorridorsLayer } from './layers/airCorridorsLayer';
import { buildSeaLanesLayer } from './layers/seaLanesLayer';
import { buildIncidentsLayers } from './layers/incidentsPulseLayer';
import { buildPatrolsLayer } from './layers/patrolsLayer';
import { buildCamerasLayer } from './layers/camerasLayer';
import { buildBuildings3dLayer } from './layers/buildings3dLayer';
import { useStore } from '../store';
import { bufferAroundPoint } from '../lib/bufferTool';
import type { UnitState } from '../types/venue';

interface MapHostProps {
  unitSnapshot: UnitState[];
  pulseT: number;
}

export function MapHost({ unitSnapshot, pulseT }: MapHostProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<MapLibreMap | null>(null);
  const [mapReady, setMapReady] = useState<MapLibreMap | null>(null);

  const venues = useStore((s) => s.venues);
  const incidents = useStore((s) => s.incidents);
  const staticGeo = useStore((s) => s.staticGeo);
  const selectedId = useStore((s) => s.selectedVenueId);
  const selectVenue = useStore((s) => s.selectVenue);
  const selectIncident = useStore((s) => s.selectIncident);
  const selectUnit = useStore((s) => s.selectUnit);
  const selectCamera = useStore((s) => s.selectCamera);
  const selectedUnitId = useStore((s) => s.selectedUnitId);
  const selectedIncidentId = useStore((s) => s.selectedIncidentId);
  const selectedCameraId = useStore((s) => s.selectedCameraId);
  const buildings3dEnabled = useStore((s) => s.buildings3dEnabled);
  const camerasEnabled = useStore((s) => s.camerasEnabled);
  const bufferEnabled = useStore((s) => s.bufferEnabled);
  const bufferRadiusKm = useStore((s) => s.bufferRadiusKm);
  const searchQuery = useStore((s) => s.searchQuery);

  useEffect(() => {
    if (!containerRef.current) return undefined;
    const map = createMap({ container: containerRef.current });
    mapRef.current = map;
    map.once('load', () => setMapReady(map));
    return () => {
      map.remove();
      mapRef.current = null;
      setMapReady(null);
    };
  }, []);

  useEffect(() => {
    if (!mapReady || !selectedId) return;
    const v = venues.find((f) => f.properties.id === selectedId);
    if (v) {
      const coords = v.geometry.coordinates as [number, number];
      flyToVenue(mapReady, coords[0], coords[1]);
    }
  }, [mapReady, selectedId, venues]);

  const filteredVenueIds = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    if (!q) return null;
    return new Set(
      venues.filter((v) => v.properties.name.toLowerCase().includes(q)).map((v) => v.properties.id),
    );
  }, [venues, searchQuery]);

  const bufferPolygon = useMemo(() => {
    if (!bufferEnabled || !selectedId) return null;
    const v = venues.find((f) => f.properties.id === selectedId);
    if (!v) return null;
    const coords = v.geometry.coordinates as [number, number];
    return bufferAroundPoint(coords[0], coords[1], bufferRadiusKm);
  }, [bufferEnabled, selectedId, bufferRadiusKm, venues]);

  const layers = useMemo<Layer[]>(() => {
    const out: Layer[] = [];

    // 3D buildings first - extruded under everything else
    if (buildings3dEnabled && staticGeo.buildings.length > 0) {
      out.push(buildBuildings3dLayer({ data: staticGeo.buildings }));
    }

    // Lanes / corridors / districts
    out.push(buildAirCorridorsLayer(staticGeo.airCorridors));
    out.push(buildSeaLanesLayer(staticGeo.seaLanes));
    out.push(buildHeliPadsLayer(staticGeo.pads));
    out.push(buildPortsLayer(staticGeo.ports));
    out.push(buildAirfieldsLayer(staticGeo.airfields));

    // Cameras
    if (camerasEnabled && staticGeo.cameras.length > 0) {
      out.push(
        ...buildCamerasLayer({
          data: staticGeo.cameras,
          selectedId: selectedCameraId,
          onClick: selectCamera,
        }),
      );
    }

    // Buffer + venues
    const buf = buildBufferLayer(bufferPolygon);
    if (buf) out.push(buf);
    out.push(
      buildVenuesLayer({
        venues,
        selectedId,
        onClick: selectVenue,
        filterIds: filteredVenueIds,
      }),
    );

    // Incidents (pulse + core)
    out.push(
      ...buildIncidentsLayers({
        data: incidents,
        pulseT,
        selectedId: selectedIncidentId,
        onClick: selectIncident,
      }),
    );

    // Patrols (halo + core)
    out.push(
      ...buildPatrolsLayer({
        data: unitSnapshot,
        selectedId: selectedUnitId,
        onClick: selectUnit,
      }),
    );

    return out;
  }, [
    buildings3dEnabled,
    camerasEnabled,
    bufferPolygon,
    venues,
    selectedId,
    selectVenue,
    selectCamera,
    selectedCameraId,
    filteredVenueIds,
    staticGeo,
    incidents,
    pulseT,
    selectedIncidentId,
    selectIncident,
    unitSnapshot,
    selectedUnitId,
    selectUnit,
  ]);

  return (
    <>
      <div ref={containerRef} className="map-canvas" />
      <DeckOverlay map={mapReady} layers={layers} />
      <div className="map-watermark">
        AKOM · MAPLIBRE · DECK.GL · {unitSnapshot.length} BİRİM · {staticGeo.buildings.length}{' '}
        BİNA · {staticGeo.cameras.length} KAMERA
      </div>
    </>
  );
}
