import { ScatterplotLayer } from '@deck.gl/layers';
import type { AirfieldFeature } from '../../types/venue';

export function buildAirfieldsLayer(
  data: AirfieldFeature[],
): ScatterplotLayer<AirfieldFeature> {
  return new ScatterplotLayer<AirfieldFeature>({
    id: 'airfields',
    data,
    pickable: true,
    stroked: true,
    filled: true,
    radiusUnits: 'pixels',
    lineWidthUnits: 'pixels',
    getPosition: (f) => f.geometry.coordinates as [number, number],
    getRadius: 9,
    getLineColor: [255, 176, 0, 220],
    getFillColor: [255, 176, 0, 40],
    getLineWidth: 1.8,
  });
}
