import { useEffect } from 'react';
import { X, ExternalLink, Radio } from 'lucide-react';
import type { CameraFeature } from '../types/venue';

interface FeedInspectorProps {
  camera: CameraFeature | null;
  onClose: () => void;
}

/**
 * Modal feed viewer for IBB live cameras. Embeds the HLS manifest as a
 * `<video>` source - browsers with native HLS (Safari, iOS) play directly;
 * Chrome/Firefox show a placeholder with the manifest URL for manual handoff
 * to a HLS-capable player. A future polish slice can wire hls.js in here.
 */
export function FeedInspector({ camera, onClose }: FeedInspectorProps) {
  useEffect(() => {
    if (!camera) return undefined;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [camera, onClose]);

  if (!camera) return null;
  const { name, district, kind, hls } = camera.properties;
  const [lon, lat] = camera.geometry.coordinates as [number, number];

  return (
    <div className="feed-modal" role="dialog" aria-modal="true" aria-labelledby="feed-modal-title">
      <div className="feed-modal__panel glass-panel glass-panel--deep">
        <header className="feed-modal__header">
          <div>
            <div className="feed-modal__title" id="feed-modal-title">
              <Radio size={14} style={{ verticalAlign: '-2px', marginRight: 6 }} />
              {name}
            </div>
            <div className="feed-modal__meta">
              {district} · {kind} · {lat.toFixed(4)}, {lon.toFixed(4)}
            </div>
          </div>
          <button type="button" className="feed-modal__close" onClick={onClose} aria-label="Kapat">
            <X size={14} /> ESC
          </button>
        </header>

        <video
          controls
          autoPlay
          muted
          playsInline
          crossOrigin="anonymous"
          style={{
            width: '100%',
            maxHeight: 360,
            background: '#000',
            borderRadius: 10,
            border: '1px solid rgba(255,255,255,0.08)',
          }}
        >
          <source src={hls} type="application/vnd.apple.mpegurl" />
        </video>

        <div className="feed-modal__placeholder">
          HLS akışı (M3U8): krom-tabanlı tarayıcılar harici oynatıcı isteyebilir
          (VLC / IINA / Safari). hls.js entegrasyonu sonraki PR'da.
        </div>

        <div className="feed-modal__url" aria-label="HLS akış adresi">
          {hls}
        </div>

        <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
          <a
            href={hls}
            target="_blank"
            rel="noreferrer noopener"
            className="map-toolbar__btn glass-panel glass-panel--float glass-panel--pill glass-panel--interactive"
            style={{ padding: '6px 12px', textDecoration: 'none' }}
          >
            <ExternalLink size={12} /> Aç
          </a>
        </div>
      </div>
    </div>
  );
}
