import { ScatterplotLayer } from '@deck.gl/layers';
import type { IncidentFeature } from '../../types/venue';

const TYPE_COLOR: Record<IncidentFeature['properties']['type'], [number, number, number]> = {
  mascal: [230, 57, 70],
  collapse: [230, 57, 70],
  fire: [255, 138, 0],
  flood: [107, 182, 255],
  leak: [255, 220, 100],
  hazmat: [200, 180, 255],
};

interface IncidentBuildArgs {
  data: IncidentFeature[];
  /** Current performance.now timestamp used to derive a sinusoidal pulse. */
  pulseT: number;
  selectedId?: string | null;
  onClick?: (id: string) => void;
}

/**
 * Two stacked ScatterplotLayers per incident: an outer expanding ring
 * (pulse) and an inner solid dot. The pulse animation is driven from
 * `pulseT` which the caller bumps via RAF.
 */
export function buildIncidentsLayers({
  data,
  pulseT,
  selectedId = null,
  onClick,
}: IncidentBuildArgs): ScatterplotLayer<IncidentFeature>[] {
  // [0,1) per 1.5s
  const t = (pulseT / 1500) % 1;
  // Ring radius: expanding 6 -> 26px, alpha fading 200 -> 0
  const ringRadius = 6 + t * 20;
  const ringAlpha = Math.round((1 - t) * 200);

  const pulse = new ScatterplotLayer<IncidentFeature>({
    id: 'incidents-pulse',
    data,
    pickable: false,
    stroked: true,
    filled: false,
    radiusUnits: 'pixels',
    lineWidthUnits: 'pixels',
    getPosition: (f) => f.geometry.coordinates as [number, number],
    getRadius: ringRadius,
    getLineColor: (f) => {
      const c = TYPE_COLOR[f.properties.type];
      return [c[0], c[1], c[2], ringAlpha];
    },
    getLineWidth: 1.4,
    updateTriggers: {
      getRadius: ringRadius,
      getLineColor: ringAlpha,
    },
  });

  const core = new ScatterplotLayer<IncidentFeature>({
    id: 'incidents-core',
    data,
    pickable: true,
    stroked: true,
    filled: true,
    radiusUnits: 'pixels',
    lineWidthUnits: 'pixels',
    getPosition: (f) => f.geometry.coordinates as [number, number],
    getRadius: (f) => (selectedId === f.properties.id ? 7 : 5),
    getFillColor: (f) => {
      const c = TYPE_COLOR[f.properties.type];
      return [c[0], c[1], c[2], 240];
    },
    getLineColor: (f) =>
      selectedId === f.properties.id ? [255, 255, 255, 230] : [10, 12, 16, 200],
    getLineWidth: 1.4,
    onClick: (info) => {
      const id = info.object?.properties.id;
      if (id) onClick?.(id);
    },
    updateTriggers: {
      getRadius: [selectedId],
      getLineColor: [selectedId],
    },
  });

  return [pulse, core];
}
