import { ScatterplotLayer } from '@deck.gl/layers';
import type { PortFeature } from '../../types/venue';

const KIND_COLOR: Record<PortFeature['properties']['kind'], [number, number, number, number]> = {
  ferry: [107, 182, 255, 220],
  cargo: [180, 200, 220, 200],
  marina: [232, 220, 196, 200],
};

export function buildPortsLayer(data: PortFeature[]): ScatterplotLayer<PortFeature> {
  return new ScatterplotLayer<PortFeature>({
    id: 'ports',
    data,
    pickable: true,
    stroked: true,
    filled: true,
    radiusUnits: 'pixels',
    lineWidthUnits: 'pixels',
    getPosition: (f) => f.geometry.coordinates as [number, number],
    getRadius: 5,
    getLineColor: (f) => KIND_COLOR[f.properties.kind],
    getFillColor: (f) => {
      const c = KIND_COLOR[f.properties.kind];
      return [c[0], c[1], c[2], 60];
    },
    getLineWidth: 1.4,
  });
}
