import { ScatterplotLayer } from '@deck.gl/layers';
import type { CameraFeature } from '../../types/venue';

const KIND_COLOR: Record<CameraFeature['properties']['kind'], [number, number, number]> = {
  Heritage: [200, 180, 255],
  Square: [255, 220, 110],
  Bridge: [107, 182, 255],
  Pier: [107, 182, 255],
  Hub: [232, 220, 196],
  Coast: [120, 220, 200],
};

interface CamerasArgs {
  data: CameraFeature[];
  selectedId?: string | null;
  onClick?: (id: string) => void;
}

export function buildCamerasLayer({
  data,
  selectedId = null,
  onClick,
}: CamerasArgs): ScatterplotLayer<CameraFeature>[] {
  const halo = new ScatterplotLayer<CameraFeature>({
    id: 'cameras-halo',
    data,
    pickable: false,
    stroked: false,
    filled: true,
    radiusUnits: 'pixels',
    getPosition: (f) => f.geometry.coordinates as [number, number],
    getRadius: 10,
    getFillColor: (f) => {
      const c = KIND_COLOR[f.properties.kind];
      return [c[0], c[1], c[2], 40];
    },
  });
  const core = new ScatterplotLayer<CameraFeature>({
    id: 'cameras-core',
    data,
    pickable: true,
    stroked: true,
    filled: true,
    radiusUnits: 'pixels',
    lineWidthUnits: 'pixels',
    getPosition: (f) => f.geometry.coordinates as [number, number],
    getRadius: (f) => (selectedId === f.properties.id ? 6 : 4),
    getFillColor: (f) => {
      const c = KIND_COLOR[f.properties.kind];
      return [c[0], c[1], c[2], 220];
    },
    getLineColor: (f) =>
      selectedId === f.properties.id ? [255, 255, 255, 240] : [10, 12, 16, 200],
    getLineWidth: 1.4,
    onClick: (info) => {
      const id = info.object?.properties.id;
      if (id) onClick?.(id);
    },
    updateTriggers: {
      getRadius: [selectedId],
      getLineColor: [selectedId],
    },
  });
  return [halo, core];
}
