import * as turf from '@turf/turf';
import type {
  BeatFeature,
  CorridorFeature,
  Modality,
  SeaLaneFeature,
  UnitFeature,
  UnitState,
} from '../types/venue';

type RouteFeature = BeatFeature | CorridorFeature | SeaLaneFeature;

interface InternalUnit {
  id: string;
  callsign: string;
  modality: Modality;
  type: string;
  status: UnitState['status'];
  speedKph: number;
  offset: number;
  beatId: string;
  alt_m?: number;
}

interface RouteCache {
  feature: RouteFeature;
  length_km: number;
}

/**
 * Pure kinematics engine - no React, no DOM. Caller drives it from a RAF
 * loop or interval. Per tick it produces a `UnitState[]` snapshot suitable
 * for a deck.gl ScatterplotLayer / IconLayer / TripsLayer.
 *
 * Each unit is bound to a closed-loop route polyline (ground beats, heli
 * corridors set up as A->B->A round trips, naval sea lanes set up the same
 * way). Position along the loop is `(offset + elapsed_hours * speed_kph /
 * length_km) mod 1`.
 */
export class PatrolEngine {
  private units: InternalUnit[] = [];
  private routes = new Map<string, RouteCache>();
  private startedAt = performance.now();

  setRoutes(routes: RouteFeature[]): void {
    this.routes.clear();
    for (const f of routes) {
      if (!f.properties?.id) continue;
      const length_km = turf.length(f, { units: 'kilometers' });
      this.routes.set(f.properties.id, { feature: f, length_km: Math.max(0.01, length_km) });
    }
  }

  setUnits(units: UnitFeature[]): void {
    this.units = units.map((f) => ({
      id: f.properties.id,
      callsign: f.properties.callsign,
      modality: f.properties.modality,
      type: f.properties.type,
      status: f.properties.status,
      speedKph: f.properties.speed_kph,
      offset: f.properties.offset,
      beatId: f.properties.beat_id,
      alt_m: f.properties.alt_m,
    }));
    this.startedAt = performance.now();
  }

  reseed(): void {
    this.startedAt = performance.now();
  }

  snapshot(nowMs: number = performance.now()): UnitState[] {
    const elapsedHours = (nowMs - this.startedAt) / 3_600_000;
    const out: UnitState[] = [];
    for (const u of this.units) {
      const route = this.routes.get(u.beatId);
      if (!route) {
        // Fall back to first coord of the beat or origin.
        out.push({
          id: u.id,
          callsign: u.callsign,
          modality: u.modality,
          type: u.type,
          status: u.status,
          lon: 0,
          lat: 0,
          heading: 0,
          speed: u.speedKph,
          alt_m: u.alt_m,
        });
        continue;
      }
      const fractionDelta = (elapsedHours * u.speedKph) / route.length_km;
      let f = (u.offset + fractionDelta) % 1;
      if (f < 0) f += 1;
      const distKm = f * route.length_km;
      const point = turf.along(route.feature, distKm, { units: 'kilometers' });
      const ahead = turf.along(
        route.feature,
        Math.min(route.length_km, distKm + 0.05),
        { units: 'kilometers' },
      );
      const heading = turf.bearing(point, ahead);
      const [lon, lat] = point.geometry.coordinates as [number, number];
      out.push({
        id: u.id,
        callsign: u.callsign,
        modality: u.modality,
        type: u.type,
        status: u.status,
        lon,
        lat,
        heading: Number.isFinite(heading) ? heading : 0,
        speed: u.speedKph,
        alt_m: u.alt_m,
      });
    }
    return out;
  }

  count(): number {
    return this.units.length;
  }
}
