import { ScatterplotLayer } from '@deck.gl/layers';
import type { PadFeature } from '../../types/venue';

const KIND_COLOR: Record<PadFeature['properties']['kind'], [number, number, number, number]> = {
  hospital: [232, 220, 196, 230],
  military: [255, 176, 0, 230],
  civil: [107, 182, 255, 220],
};

export function buildHeliPadsLayer(data: PadFeature[]): ScatterplotLayer<PadFeature> {
  return new ScatterplotLayer<PadFeature>({
    id: 'heli-pads',
    data,
    pickable: true,
    stroked: true,
    filled: true,
    radiusUnits: 'pixels',
    lineWidthUnits: 'pixels',
    getPosition: (f) => f.geometry.coordinates as [number, number],
    getRadius: 6,
    getLineColor: (f) => KIND_COLOR[f.properties.kind],
    getFillColor: (f) => {
      const c = KIND_COLOR[f.properties.kind];
      return [c[0], c[1], c[2], 40];
    },
    getLineWidth: 1.5,
  });
}
