import { PathLayer } from '@deck.gl/layers';
import type { CorridorFeature } from '../../types/venue';

interface CorridorRow {
  id: string;
  modality: 'heli' | 'fixed';
  path: [number, number][];
}

export function buildAirCorridorsLayer(features: CorridorFeature[]): PathLayer<CorridorRow> {
  const rows: CorridorRow[] = features.map((f) => ({
    id: f.properties.id,
    modality: f.properties.modality,
    path: (f.geometry.coordinates as [number, number][]).map(([lon, lat]) => [lon, lat]),
  }));
  return new PathLayer<CorridorRow>({
    id: 'air-corridors',
    data: rows,
    pickable: false,
    widthUnits: 'pixels',
    getPath: (d) => d.path,
    getColor: (d) =>
      d.modality === 'heli' ? [255, 220, 100, 90] : [200, 180, 255, 80],
    getWidth: 1.3,
    // No native dash in PathLayer; emulate visual lightness with width + alpha.
    capRounded: true,
    jointRounded: true,
  });
}
