import { now, getLocalTimeZone, type ZonedDateTime } from '@internationalized/date';

export const TZ = 'Europe/Istanbul';

export function tzNow(): ZonedDateTime {
  return now(TZ);
}

export function localNow(): ZonedDateTime {
  return now(getLocalTimeZone());
}

const MONTH_CODE = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN', 'JUL', 'AUG', 'SEP', 'OCT', 'NOV', 'DEC'];

function pad(n: number, w = 2): string {
  return String(n).padStart(w, '0');
}

/**
 * NATO-style Date-Time Group, Zulu by default.
 *   "10MAY26 14:32Z"
 */
export function dtg(d: ZonedDateTime = tzNow()): string {
  const utc = d.toDate();
  const day = pad(utc.getUTCDate());
  const month = MONTH_CODE[utc.getUTCMonth()] ?? '???';
  const year = pad(utc.getUTCFullYear() % 100);
  const hh = pad(utc.getUTCHours());
  const mm = pad(utc.getUTCMinutes());
  return `${day}${month}${year} ${hh}:${mm}Z`;
}

export function hhmmss(d: ZonedDateTime = tzNow()): string {
  return `${pad(d.hour)}:${pad(d.minute)}:${pad(d.second)}`;
}

export function tickElapsed(startMs: number, nowMs: number = Date.now()): string {
  const s = Math.max(0, Math.floor((nowMs - startMs) / 1000));
  const m = Math.floor(s / 60);
  const r = s % 60;
  return `T+${pad(m)}:${pad(r)}`;
}
