import type { ReactNode } from 'react';
import { Sparkline } from './Sparkline';

interface KpiTileProps {
  label: string;
  value: ReactNode;
  unit?: string;
  state?: 'normal' | 'okay' | 'critical';
  sparkValues?: number[];
}

export function KpiTile({ label, value, unit, state = 'normal', sparkValues = [] }: KpiTileProps) {
  return (
    <div className="kpi-tile glass-panel glass-panel--tile glass-panel--float" data-state={state}>
      <div className="kpi-tile__label">{label}</div>
      <div>
        <span className="kpi-tile__value">{value}</span>
        {unit ? <span className="kpi-tile__unit">{unit}</span> : null}
      </div>
      <Sparkline className="kpi-tile__spark" values={sparkValues} />
    </div>
  );
}
