import { useStore } from '../../store';
import { SearchBar } from '../SearchBar';
import { MapToolbar } from '../MapToolbar';
import { MapHost } from '../../map/MapHost';
import { VenueList } from '../VenueList';
import { tickElapsed } from '../../lib/time';
import type { UnitState } from '../../types/venue';

interface OperasyonProps {
  unitSnapshot: UnitState[];
  pulseT: number;
}

function IncidentsPanel() {
  const incidents = useStore((s) => s.incidents);
  const select = useStore((s) => s.selectIncident);
  const selectedId = useStore((s) => s.selectedIncidentId);

  return (
    <section className="ops-panel glass-panel glass-panel--deep">
      <div className="ops-panel__title">Aktif Olaylar &middot; {incidents.length}</div>
      {incidents.length === 0 && (
        <div style={{ color: 'var(--bone-faint)', fontSize: 'var(--t-tiny)' }}>
          Aktif olay yok &middot; sistem nominal.
        </div>
      )}
      {incidents.map((inc) => {
        const isActive = selectedId === inc.properties.id;
        const start = Date.parse(inc.properties.start) || Date.now();
        return (
          <div
            key={inc.properties.id}
            className="incident-row glass-panel glass-panel--card glass-panel--klaxon glass-panel--interactive"
            data-active={isActive}
            style={{ cursor: 'pointer', opacity: isActive ? 1 : 0.92 }}
            onClick={() => select(inc.properties.id)}
          >
            <span className="incident-row__dot" />
            <span className="incident-row__name">{inc.properties.label}</span>
            <span className="incident-row__eta">{tickElapsed(start)}</span>
          </div>
        );
      })}
    </section>
  );
}

function ModalityBreakdown({ snapshot }: { snapshot: UnitState[] }) {
  const counts = snapshot.reduce(
    (acc, u) => {
      acc[u.modality] = (acc[u.modality] ?? 0) + 1;
      return acc;
    },
    { ground: 0, heli: 0, fixed: 0, naval: 0 } as Record<UnitState['modality'], number>,
  );

  const rows: { id: string; label: string; count: number; color: string }[] = [
    { id: 'ground', label: 'Kara', count: counts.ground, color: 'var(--amber)' },
    { id: 'heli', label: 'Heli', count: counts.heli, color: 'rgb(255, 220, 110)' },
    { id: 'fixed', label: 'Sabit Kanat', count: counts.fixed, color: 'rgb(200, 180, 255)' },
    { id: 'naval', label: 'Deniz', count: counts.naval, color: 'rgb(107, 182, 255)' },
  ];

  return (
    <section className="ops-panel glass-panel glass-panel--deep">
      <div className="ops-panel__title">Modalite Dağılımı &middot; {snapshot.length} birim</div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
        {rows.map((r) => (
          <div
            key={r.id}
            style={{
              display: 'grid',
              gridTemplateColumns: '8px 1fr auto',
              alignItems: 'center',
              gap: 8,
              padding: '4px 8px',
              background: 'var(--bg-panel-soft)',
              borderLeft: `2px solid ${r.color}`,
            }}
          >
            <span style={{ width: 6, height: 6, background: r.color, borderRadius: '50%' }} />
            <span
              style={{
                fontFamily: 'var(--font-mono)',
                fontSize: 'var(--t-small)',
                color: 'var(--bone)',
              }}
            >
              {r.label}
            </span>
            <span
              style={{
                fontFamily: 'var(--font-mono)',
                fontSize: 'var(--t-tiny)',
                color: 'var(--amber)',
              }}
            >
              {r.count}
            </span>
          </div>
        ))}
      </div>
    </section>
  );
}

function VenuesPanel() {
  return (
    <section className="ops-panel glass-panel glass-panel--deep">
      <div className="ops-panel__title">Mekanlar &middot; Etkilenen Alan</div>
      <VenueList />
    </section>
  );
}

export function Operasyon({ unitSnapshot, pulseT }: OperasyonProps) {
  return (
    <>
      <section className="hud-pane hud-pane--map">
        <div className="map-host">
          <MapHost unitSnapshot={unitSnapshot} pulseT={pulseT} />
          <MapToolbar />
          <SearchBar />
        </div>
      </section>
      <aside className="hud-pane hud-pane--side">
        <IncidentsPanel />
        <ModalityBreakdown snapshot={unitSnapshot} />
        <VenuesPanel />
      </aside>
    </>
  );
}
