import { useEffect, useMemo, useState } from 'react';
import { useStore, type TabId } from '../store';
import { dtg } from '../lib/time';
import { Operasyon } from './tabs/Operasyon';
import { Kure } from './tabs/Kure';
import { PlaceholderTab } from './tabs/PlaceholderTab';
import { KpiTile } from './KpiTile';
import { RadioLog } from './RadioLog';
import { FeedInspector } from './FeedInspector';
import type { UnitState } from '../types/venue';

interface HudShellProps {
  unitSnapshot: UnitState[];
  pulseT: number;
}

interface TabSpec {
  id: TabId;
  short: string;
  long: string;
  code: string;
}

const TABS: TabSpec[] = [
  { id: 'operasyon', short: 'OPS', long: 'Operasyon', code: '01' },
  { id: 'goruntuleme', short: 'GÖRÜ', long: 'Görüntüleme', code: '02' },
  { id: 'haberlesme', short: 'HBR', long: 'Haberleşme', code: '03' },
  { id: 'adli', short: 'ADLİ', long: 'Adli Analiz', code: '04' },
  { id: 'kayit', short: 'KAYIT', long: 'Kayıt / Replay', code: '05' },
  { id: 'altyapi', short: 'ALTYP', long: 'Altyapı', code: '06' },
  { id: 'c2', short: 'C2', long: 'Komuta Kontrol', code: '07' },
  { id: 'kure', short: 'KÜRE', long: 'Küresel Görüntü', code: '08' },
];

function TitleBar({ tickClock }: { tickClock: string }) {
  const incidents = useStore((s) => s.incidents);
  const mascalActive = incidents.some((i) => i.properties.type === 'mascal');

  return (
    <header className="hud-titlebar">
      <div className="hud-titlebar__brand">
        <span className="hud-titlebar__brand-mark" aria-hidden="true" />
        <span style={{ color: 'var(--amber)', fontWeight: 600, letterSpacing: '0.14em' }}>AKOM</span>
        <span style={{ color: 'var(--bone-mute)' }}>· Afet Koordinasyon Merkezi</span>
        <span className="hud-titlebar__dtg" aria-live="polite">
          DTG: {tickClock}
        </span>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
        {mascalActive && (
          <span className="hud-titlebar__mascal" role="alert">
            ▲ MASCAL · AKTİF
          </span>
        )}
        <span className="hud-titlebar__user">tugay·öztürk · KOMUTA</span>
      </div>
    </header>
  );
}

function TabBar() {
  const active = useStore((s) => s.activeTab);
  const setActive = useStore((s) => s.setActiveTab);

  return (
    <nav className="hud-tabbar" aria-label="Cockpit sekmeleri">
      {TABS.map((t) => (
        <button
          key={t.id}
          type="button"
          className="hud-tab"
          data-active={active === t.id}
          onClick={() => setActive(t.id)}
          aria-current={active === t.id ? 'page' : undefined}
        >
          <span className="hud-tab__id">{t.code}</span>
          <span>{t.short}</span>
        </button>
      ))}
    </nav>
  );
}

function KpiRibbon() {
  const k = useStore((s) => s.kpis);
  const s = useStore((s) => s.sparklines);

  const etaStr =
    k.etaAvgSec > 0
      ? `${String(Math.floor(k.etaAvgSec / 60)).padStart(2, '0')}:${String(
          Math.floor(k.etaAvgSec % 60),
        ).padStart(2, '0')}`
      : '--:--';
  const roadState: 'normal' | 'critical' | 'okay' =
    k.roadsBlockedPct >= 30 ? 'critical' : k.roadsBlockedPct <= 5 ? 'okay' : 'normal';

  return (
    <div className="hud-ribbon" role="region" aria-label="Anahtar göstergeler">
      <KpiTile label="Birim" value={k.units} unit="biri̇m" sparkValues={s.units} />
      <KpiTile
        label="Olay"
        value={k.incidents}
        state={k.incidents > 0 ? 'critical' : 'okay'}
        sparkValues={s.incidents}
      />
      <KpiTile label="ETA Avg" value={etaStr} sparkValues={s.eta} />
      <KpiTile
        label="Hasta Yatak"
        value={k.bedsAvailable.toLocaleString('tr-TR')}
        sparkValues={s.beds}
      />
      <KpiTile
        label="Kapalı Yol"
        value={`%${k.roadsBlockedPct.toFixed(0)}`}
        state={roadState}
        sparkValues={s.roads}
      />
      <KpiTile label="MGM" value={k.wxLabel} />
    </div>
  );
}

function TabSurface({ unitSnapshot, pulseT }: HudShellProps) {
  const active = useStore((s) => s.activeTab);
  switch (active) {
    case 'operasyon':
      return <Operasyon unitSnapshot={unitSnapshot} pulseT={pulseT} />;
    case 'goruntuleme':
      return (
        <PlaceholderTab
          label="Görüntüleme · İBB Kameraları"
          description="Canlı kamera ağı, OSINT akışları ve hava kalitesi katmanı bu sekmeden yönetilecek."
          features={['İBB MOBESE canlı feed', 'OSINT trend', 'Hava kalitesi & gürültü', 'Termal overlay']}
        />
      );
    case 'haberlesme':
      return (
        <PlaceholderTab
          label="Haberleşme"
          description="Telsiz logu, mesaj yönlendirme ve telsiz frekans matrisi."
          features={['Telsiz log akışı', 'Yönlendirilmiş mesaj', 'Frekans matrisi', 'CRSF backhaul']}
        />
      );
    case 'adli':
      return (
        <PlaceholderTab
          label="Adli Analiz"
          description="Binalar, hasar sınıfları, yaş demografisi ve adli zaman çizelgesi."
          features={['KRDAE hasar dağılımı', 'Bina yaşı × hasar histogramı', 'Şahit kayıtları']}
        />
      );
    case 'kayit':
      return (
        <PlaceholderTab
          label="Kayıt / Replay"
          description="T-24h artçı sarsıntı + dispatch zaman tüneli, fırça aracıyla."
          features={['Replay brush', 'Artçı sarsıntı', 'Dispatch zaman çizelgesi']}
        />
      );
    case 'altyapi':
      return (
        <PlaceholderTab
          label="Altyapı"
          description="Elektrik, su, doğalgaz, telekom &mdash; akış ağı durum tablosu."
          features={['Şebeke durumu', 'Su kaynak yolu', 'Telekom & 4G/5G', 'Kritik düğüm sıralaması']}
        />
      );
    case 'c2':
      return (
        <PlaceholderTab
          label="C2 · Komuta Kontrol"
          description="Deliberate / Dynamic / Pending / Paired / Execution panosu (Kanban)."
          features={['Görev kartları', 'Sürükle-bırak akış', 'C2 önceliklendirme']}
        />
      );
    case 'kure':
      return <Kure unitSnapshot={unitSnapshot} pulseT={pulseT} />;
  }
}

function Footer() {
  return (
    <footer className="hud-footer" role="contentinfo">
      <RadioLog />
    </footer>
  );
}

export function HudShell({ unitSnapshot, pulseT }: HudShellProps) {
  const [clock, setClock] = useState(() => dtg());
  const cameras = useStore((s) => s.staticGeo.cameras);
  const selectedCameraId = useStore((s) => s.selectedCameraId);
  const selectCamera = useStore((s) => s.selectCamera);

  useEffect(() => {
    const id = window.setInterval(() => setClock(dtg()), 1000);
    return () => window.clearInterval(id);
  }, []);

  const activeCamera = useMemo(() => {
    if (!selectedCameraId) return null;
    return cameras.find((c) => c.properties.id === selectedCameraId) ?? null;
  }, [selectedCameraId, cameras]);

  return (
    <div className="hud-shell">
      <TitleBar tickClock={clock} />
      <TabBar />
      <div className="hud-body">
        <KpiRibbon />
        <TabSurface unitSnapshot={unitSnapshot} pulseT={pulseT} />
      </div>
      <Footer />
      <FeedInspector camera={activeCamera} onClose={() => selectCamera(null)} />
    </div>
  );
}
