import { GeoJsonLayer } from '@deck.gl/layers';
import type { BufferPolygon } from '../../lib/bufferTool';

export function buildBufferLayer(polygon: BufferPolygon | null): GeoJsonLayer | null {
  if (!polygon) return null;
  return new GeoJsonLayer({
    id: 'venue-buffer',
    data: polygon,
    stroked: true,
    filled: true,
    pickable: false,
    getFillColor: [255, 176, 0, 30],
    getLineColor: [255, 176, 0, 180],
    getLineWidth: 1.5,
    lineWidthUnits: 'pixels',
  });
}
