import { useEffect, useMemo, useRef, useState } from 'react';
import { HudShell } from './ui/HudShell';
import { useStore } from './store';
import { loadVenues, loadUnits, loadIncidents, loadStaticGeo, loadBuildings } from './bootstrap/loadData';
import { generateRadio } from './bootstrap/seedRadio';
import { startKpiPump } from './bootstrap/seedKpis';
import { PatrolEngine } from './sim/PatrolEngine';
import { usePatrolEngine } from './sim/usePatrolEngine';

export function App() {
  const setVenues = useStore((s) => s.setVenues);
  const setUnits = useStore((s) => s.setUnits);
  const setIncidents = useStore((s) => s.setIncidents);
  const setStaticGeo = useStore((s) => s.setStaticGeo);
  const setBuildings = useStore((s) => s.setBuildings);
  const pushRadio = useStore((s) => s.pushRadio);
  const setReducedMotion = useStore((s) => s.setReducedMotion);
  const reducedMotion = useStore((s) => s.reducedMotion);
  const units = useStore((s) => s.units);
  const staticGeo = useStore((s) => s.staticGeo);

  const engine = useMemo(() => new PatrolEngine(), []);
  const [pulseT, setPulseT] = useState(0);

  useEffect(() => {
    let cancelled = false;
    void (async () => {
      // 1. Cheap stuff first - HUD goes interactive in <300 ms
      const [venues, unitFeatures, incidents, geo] = await Promise.all([
        loadVenues(),
        loadUnits(),
        loadIncidents(),
        loadStaticGeo(),
      ]);
      if (cancelled) return;
      setVenues(venues);
      setUnits(unitFeatures);
      setIncidents(incidents);
      setStaticGeo(geo);

      // 2. Buildings (12 MB) lazy-loaded when the browser is idle. We don't
      //    block the first paint on this. Falls back to setTimeout when
      //    requestIdleCallback isn't available (Safari, Firefox <55).
      const startBuildings = () => {
        if (cancelled) return;
        void loadBuildings().then((b) => {
          if (!cancelled) setBuildings(b);
        });
      };
      type IdleWindow = Window & { requestIdleCallback?: (cb: () => void, opts?: { timeout: number }) => void };
      const w = window as IdleWindow;
      if (typeof w.requestIdleCallback === 'function') {
        w.requestIdleCallback(startBuildings, { timeout: 4000 });
      } else {
        setTimeout(startBuildings, 1200);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [setVenues, setUnits, setIncidents, setStaticGeo, setBuildings]);

  useEffect(() => {
    const routes = [
      ...staticGeo.airCorridors,
      ...staticGeo.seaLanes,
      ...staticGeo.groundBeats,
    ];
    if (routes.length === 0 || units.length === 0) return;
    engine.setRoutes(routes);
    engine.setUnits(units);
  }, [engine, units, staticGeo]);

  useEffect(() => {
    const mq = window.matchMedia('(prefers-reduced-motion: reduce)');
    setReducedMotion(mq.matches);
    const h = (e: MediaQueryListEvent) => setReducedMotion(e.matches);
    mq.addEventListener('change', h);
    return () => mq.removeEventListener('change', h);
  }, [setReducedMotion]);

  useEffect(() => {
    pushRadio(generateRadio());
    const id = window.setInterval(() => pushRadio(generateRadio()), 6000);
    return () => window.clearInterval(id);
  }, [pushRadio]);

  useEffect(() => startKpiPump(() => useStore.getState().reducedMotion), []);

  // Klaxon pulse clock - 10 Hz so layer rebuilds stay cheap.
  const pulseRafRef = useRef(0);
  const lastPulseRef = useRef(0);
  useEffect(() => {
    const intervalMs = reducedMotion ? 1000 : 100;
    const step = (now: number) => {
      if (now - lastPulseRef.current >= intervalMs) {
        lastPulseRef.current = now;
        setPulseT(reducedMotion ? 0 : now);
      }
      pulseRafRef.current = requestAnimationFrame(step);
    };
    pulseRafRef.current = requestAnimationFrame(step);
    return () => cancelAnimationFrame(pulseRafRef.current);
  }, [reducedMotion]);

  const enginePrimed =
    units.length > 0 &&
    staticGeo.airCorridors.length + staticGeo.seaLanes.length + staticGeo.groundBeats.length > 0;

  const snapshot = usePatrolEngine({
    engine,
    reactHz: 10,
    reducedMotion,
    enabled: enginePrimed,
  });

  return <HudShell unitSnapshot={snapshot} pulseT={pulseT} />;
}
