import type {
  AirfieldFeature,
  BeatFeature,
  CameraFeature,
  CorridorFeature,
  IncidentFeature,
  PadFeature,
  PortFeature,
  SeaLaneFeature,
  UnitFeature,
  VenueFeature,
} from '../types/venue';
import type { BuildingFeature } from '../map/layers/buildings3dLayer';

interface FeatureCollectionRaw {
  type: 'FeatureCollection';
  features: unknown[];
}

function assetUrl(path: string): string {
  const base = import.meta.env.BASE_URL || '/';
  const clean = path.startsWith('/') ? path.slice(1) : path;
  return `${base}${clean}`;
}

async function fetchFeatures<T>(path: string, silent = false): Promise<T[]> {
  const url = assetUrl(path);
  try {
    const res = await fetch(url);
    if (!res.ok) {
      if (!silent) console.warn(`[loadData] ${url} -> HTTP ${res.status}`);
      return [];
    }
    const body = (await res.json()) as FeatureCollectionRaw;
    if (!body || !Array.isArray(body.features)) return [];
    return body.features as T[];
  } catch (err) {
    if (!silent) console.warn(`[loadData] ${url} -> ${(err as Error).message}`);
    return [];
  }
}

export interface StaticGeoBundle {
  pads: PadFeature[];
  ports: PortFeature[];
  airfields: AirfieldFeature[];
  airCorridors: CorridorFeature[];
  seaLanes: SeaLaneFeature[];
  groundBeats: BeatFeature[];
  cameras: CameraFeature[];
}

export async function loadVenues(): Promise<VenueFeature[]> {
  return fetchFeatures<VenueFeature>('data/venues.geojson');
}

export async function loadUnits(): Promise<UnitFeature[]> {
  return fetchFeatures<UnitFeature>('data/units.geojson', true);
}

export async function loadIncidents(): Promise<IncidentFeature[]> {
  return fetchFeatures<IncidentFeature>('data/incidents.geojson', true);
}

/**
 * Loads the cheap features for instant interactivity. The 12 MB buildings
 * dataset is intentionally NOT loaded here — see `loadBuildings()`.
 */
export async function loadStaticGeo(): Promise<StaticGeoBundle> {
  const [pads, ports, airfields, airCorridors, seaLanes, groundBeats, cameras] =
    await Promise.all([
      fetchFeatures<PadFeature>('data/heli-pads.geojson', true),
      fetchFeatures<PortFeature>('data/ports.geojson', true),
      fetchFeatures<AirfieldFeature>('data/airfields.geojson', true),
      fetchFeatures<CorridorFeature>('data/air-corridors.geojson', true),
      fetchFeatures<SeaLaneFeature>('data/sea-lanes.geojson', true),
      fetchFeatures<BeatFeature>('data/ground-beats.geojson', true),
      fetchFeatures<CameraFeature>('data/cameras.geojson', true),
    ]);
  return { pads, ports, airfields, airCorridors, seaLanes, groundBeats, cameras };
}

/**
 * Heavy 12 MB OSM buildings dataset. Caller is expected to defer this until
 * the cockpit is interactive (e.g. requestIdleCallback or post-paint).
 * Returns empty array on failure - building layer simply doesn't render.
 */
export async function loadBuildings(): Promise<BuildingFeature[]> {
  return fetchFeatures<BuildingFeature>('data/buildings.geojson', true);
}
