export interface CreateGlobeOptions {
  container: HTMLDivElement;
  center?: [number, number];
  zoom?: number;
  bearing?: number;
  pitch?: number;
}

export function createGlobeMap(opts: CreateGlobeOptions): MapLibreMap {
  const style = globeStyle();
  const map = new maplibregl.Map({
    container: opts.container,
    style,
    center: opts.center ?? ISTANBUL_CENTER,
    zoom: opts.zoom ?? GLOBE_INITIAL_ZOOM,
    bearing: opts.bearing ?? 0,
    pitch: opts.pitch ?? 0,
    minZoom: 0,
    maxZoom: 16,
    maxPitch: 75,
    attributionControl: { compact: true },
    fadeDuration: 200,
    hash: false,
  });

  // Force globe projection explicitly after load. Some MapLibre v5 builds
  // honor projection from style root, others only after setProjection.
  map.on('style.load', () => {
    try {
      map.setProjection({ type: 'globe' });
    } catch (err) {
      console.warn('[globeController] setProjection failed:', err);
    }
  });

  map.addControl(
    new maplibregl.NavigationControl({ visualizePitch: true, showCompass: true }),
    'bottom-right',
  );

  map.dragRotate.enable();
  map.touchZoomRotate.enableRotation();

  return map;
}

export function flyToRegion(
  map: MapLibreMap,
  center: [number, number],
  zoom = 5,
): void {
  map.flyTo({
    center,
    zoom,
    speed: 0.6,
    curve: 1.6,
    pitch: zoom < 4 ? 0 : 45,
  });
}

export { ISTANBUL_CENTER as GLOBE_HOME, GLOBE_INITIAL_ZOOM };
